-- Index 1: Messages by waConversationId + timestamp (Inbox message loading)
-- The existing idx_msg_wa_conv only has waConversationId, adding timestamp for ORDER BY coverage
CREATE INDEX IF NOT EXISTS idx_msg_wa_conv_ts ON messages (waConversationId, timestamp DESC);

-- Index 2: Messages dedup check (sessionId + messageId) - already exists as idx_unique_msgid_session

-- Index 3: wa_conversations inbox query covering index
-- The existing idx_wc_tenant_session already covers (tenantId, sessionId, lastMessageAt)
-- Add index for mergedIntoId filter + lastMessageAt sort
CREATE INDEX IF NOT EXISTS idx_wc_inbox ON wa_conversations (tenantId, sessionId, mergedIntoId, lastMessageAt DESC);

-- Index 4: Notifications with createdAt for pagination (currently using OFFSET)
CREATE INDEX IF NOT EXISTS idx_notif_tenant_created ON notifications (tenantId, isRead, createdAt DESC);

-- Index 5: Messages by tenantId + timestamp for tenant-wide queries
CREATE INDEX IF NOT EXISTS idx_msg_tenant_ts ON messages (tenantId, timestamp DESC);

-- Index 6: wa_conversations by assignedUserId + lastMessageAt for agent-filtered inbox
CREATE INDEX IF NOT EXISTS idx_wc_assigned_ts ON wa_conversations (tenantId, assignedUserId, lastMessageAt DESC);

